Rule.Source:
  import sailpoint.object.Identity;
  import sailpoint.object.Custom;
  import sailpoint.tools.Util;


  String identityCompany = "";
  String identityMinistry = "";
  if(null != identity){
    identityCompany = identity.getStringAttribute("company");
    identityMinistry = identity.getStringAttribute("ministry");
    if(Util.isNotNullOrEmpty(identityMinistry)){
      Custom custom = context.getObjectByName(Custom.class, "Ascension-custom-generalConfiguration");
      HashMap companies = new HashMap();
      if(custom != null ){
        if( custom.get("SnowCompanyMapping") !=null){
          companies = custom.get("SnowCompanyMapping");
        }
        //comment decache //context.decache(custom);
      }

      if(!Util.isEmpty(companies) && Util.isNotNullOrEmpty(companies.get(identityMinistry))){
        identityCompany = companies.get(identityMinistry);         
      }
      if(Util.nullSafeCaseInsensitiveEq(identityMinistry,"CHIMCO")){
        identityCompany = "MOSTL";         
      }
    }
  }

  return identityCompany;
